arguments.argument:
if global.gamePaused=false
{
  spikeTFol.x=x-20
  spikeTFol.y=y+28
  
  if atkProg=0 //Check if player is close
  {
    if findTargetX<atkDistX and y<oPlayer1.y and findTargetY<(maxDrop+40)*1.2
    {
      yVel=atkSpeed
      atkProg+=1
    }
  }
  else if atkProg=1 //Falling
  {
    //Reach chain end
    var fallDist;
    fallDist=y-ystart
    if fallDist>=maxDrop
    {
      yVel=0
      atkProg+=1
      exit;
    }
    //Hit player
    if prevY=y
    {
      hangTime+=1
      if hangTime>=5
      {
        yVel=0
        atkProg+=1
        exit;
      }
    }
    prevY=y
    //Hit solid
    if isCollisionBottom(1)
    {
      yVel=0
      atkProg+=1
      exit;
    }
  }
  else if atkProg=2 //Wait - Down
  {
    atkTime+=1
    if atkTime=20
    {
      yVel=-atkSpeed/3.5
      atkTime=0
      y-=1
      atkProg+=1
    }
  }
  else if atkProg=3 //Return
  {
    if y<=yCenter
    {
      prevY=0
      hangTime=0
      y=yCenter
      yVel=0
      atkProg+=1
    }
  }
  else if atkProg=4 //Wait - Up
  {
    atkTime+=1
    if atkTime=5
    {
      atkTime=0
      prevY=0
      hangTime=0
      atkProg=0
    }
  }
}
